    12→)
    13→
    14→type pluginFactoryFunc func(p *plugins.FoundBundle, pluginClass plugins.Class, sig plugins.Signature) (*plugins.Plugin, error)
    15→
    16→// DefaultPluginFactory is the default plugin factory used by the Construct step of the Bootstrap stage.
    17→//
    18→// It creates the plugin using plugin information found during the Discovery stage and makes use of the assetPath
    19→// service to set the plugin's BaseURL, Module, Logos and Screenshots fields.
    20→type DefaultPluginFactory struct {
    21→	assetProvider pluginassets.Provider
    22→	features      *config.Features
    23→}
    24→
    25→// NewDefaultPluginFactory returns a new DefaultPluginFactory.
    26→func NewDefaultPluginFactory(features *config.Features, assetProvider pluginassets.Provider) *DefaultPluginFactory {
    27→	return &DefaultPluginFactory{assetProvider: assetProvider, features: features}
    28→}
    29→
    30→func (f *DefaultPluginFactory) createPlugin(bundle *plugins.FoundBundle, class plugins.Class,
    31→	sig plugins.Signature) (*plugins.Plugin, error) {
    32→	parentInfo := pluginassets.NewPluginInfo(bundle.Primary.JSONData, class, bundle.Primary.FS, nil)
    33→	plugin, err := f.newPlugin(bundle.Primary, class, sig, parentInfo)
    34→	if err != nil {
    35→		return nil, err
    36→	}
    37→
    38→	if len(bundle.Children) == 0 {
    39→		return plugin, nil
    40→	}
    41→
    42→	plugin.Children = make([]*plugins.Plugin, 0, len(bundle.Children))
    43→	for _, child := range bundle.Children {
    44→		childInfo := pluginassets.NewPluginInfo(child.JSONData, class, child.FS, &parentInfo)
    45→		cp, err := f.newPlugin(*child, class, sig, childInfo)
    46→		if err != nil {
    47→			return nil, err
    48→		}
    49→		cp.Parent = plugin
    50→		plugin.Children = append(plugin.Children, cp)
    51→	}
    52→
    53→	return plugin, nil
    54→}
    55→
    56→func (f *DefaultPluginFactory) newPlugin(p plugins.FoundPlugin, class plugins.Class, sig plugins.Signature,
    57→	info pluginassets.PluginInfo) (*plugins.Plugin, error) {
    58→	baseURL, err := f.assetProvider.AssetPath(info)
    59→	if err != nil {
    60→		return nil, fmt.Errorf("base url: %w", err)
    61→	}
    62→	moduleURL, err := f.assetProvider.Module(info)
    63→	if err != nil {
    64→		return nil, fmt.Errorf("module url: %w", err)
    65→	}
    66→	plugin := &plugins.Plugin{
    67→		JSONData:      p.JSONData,
    68→		Class:         class,
    69→		FS:            p.FS,
    70→		BaseURL:       baseURL,
    71→		Module:        moduleURL,
    72→		Signature:     sig.Status,
    73→		SignatureType: sig.Type,
    74→		SignatureOrg:  sig.SigningOrg,
    75→	}
    76→
    77→	plugin.SetLogger(log.New(fmt.Sprintf("plugin.%s", plugin.ID)))
    78→	if err = setImages(plugin, f.assetProvider, info); err != nil {
    79→		return nil, err
    80→	}
    81→
    82→	if err := setTranslations(plugin, f.assetProvider, info); err != nil {
    83→		return nil, err
    84→	}
    85→
    86→	return plugin, nil
    87→}
