    89→func setImages(p *plugins.Plugin, assetProvider pluginassets.Provider, info pluginassets.PluginInfo) error {
    90→	var err error
    91→	for _, dst := range []*string{&p.Info.Logos.Small, &p.Info.Logos.Large} {
    92→		if len(*dst) == 0 {
    93→			*dst = defaultLogoPath(p.Type)
    94→			continue
    95→		}
    96→
    97→		*dst, err = assetProvider.AssetPath(info, *dst)
    98→		if err != nil {
    99→			return fmt.Errorf("logo: %w", err)
   100→		}
   101→	}
   102→	for i := 0; i < len(p.Info.Screenshots); i++ {
   103→		screenshot := &p.Info.Screenshots[i]
   104→		screenshot.Path, err = assetProvider.AssetPath(info, screenshot.Path)
   105→		if err != nil {
   106→			return fmt.Errorf("screenshot %d relative url: %w", i, err)
   107→		}
   108→	}
   109→	return nil
   110→}
   111→
   112→func setTranslations(p *plugins.Plugin, assetProvider pluginassets.Provider, info pluginassets.PluginInfo) error {
   113→	translations, err := getTranslations(assetProvider, info)
   114→	if err != nil {
   115→		return fmt.Errorf("set translations: %w", err)
   116→	}
   117→
   118→	p.Translations = translations
   119→	return nil
   120→}
